  1	import * as React from 'react';
  2	import {
  3	  FormGroup,
  4	  FormHelperText,
  5	  HelperText,
  6	  HelperTextItem,
  7	  gridItemSpanValueShape,
  8	} from '@patternfly/react-core';
  9	import { FieldArray, useFormikContext, FormikValues } from 'formik';
 10	import * as _ from 'lodash';
 11	
 12	import { getSpans } from './multicolumn-field-utils';
 13	import MultiColumnFieldFooter from './MultiColumnFieldFooter';
 14	import MultiColumnFieldHeader from './MultiColumnFieldHeader';
 15	import MultiColumnFieldRow from './MultiColumnFieldRow';
 16	import './MultiColumnField.scss';
 17	import { MultiColumnFieldProps } from './types';
 18	import { useFormikValidationFix } from './formik-validation-fix';
 19	import SecondaryStatus from './SecondaryStatus';
 20	
 21	const MultiColumnField: React.FC<MultiColumnFieldProps> = ({
 22	  children,
 23	  name,
 24	  label,
 25	  helpText,
 26	  required,
 27	  addLabel,
 28	  headers,
 29	  emptyValues,
 30	  emptyMessage,
 31	  isReadOnly,
 32	  disableDeleteRow,
 33	  tooltipDeleteRow,
 34	  disableAddRow,
 35	  tooltipAddRow,
 36	  spans,
 37	  complexFields,
 38	  rowRenderer,
 39	  ...props
 40	}) => {
 41	  const { values } = useFormikContext<FormikValues>();
 42	  const fieldValue = _.get(values, name, []);
 43	  const totalFieldCount: gridItemSpanValueShape = React.Children.count(
 44	    children,
 45	  ) as gridItemSpanValueShape;
 46	  const fieldSpans = spans || getSpans(totalFieldCount);
 47	  useFormikValidationFix(fieldValue);
 48	  return (
 49	    <FieldArray
 50	      name={name}
 51	      render={({ push, remove }) => {
 52	        return (
 53	          <FormGroup
 54	            data-test={props['data-test'] || 'multicolumn-field'}
 55	            fieldId={`form-multi-column-input-${name.replace(
 56	              /\./g,
 57	              '-',
 58	            )}-field`}
 59	            label={label}
 60	            isRequired={required}
 61	          >
 62	            {fieldValue.length < 1 ? (
 63	              emptyMessage && (
 64	                <div className="odc-multi-column-field__empty-message">
 65	                  <SecondaryStatus status={emptyMessage} />
 66	                </div>
 67	              )
 68	            ) : (
 69	              <MultiColumnFieldHeader headers={headers} spans={fieldSpans} />
 70	            )}
 71	            {fieldValue.length > 0 &&
 72	              fieldValue.map((value, index) => (
 73	                <MultiColumnFieldRow
 74	                  key={`${index.toString()}`} // There is no other usable value for key prop in this case.
 75	                  name={name}
 76	                  rowIndex={index}
 77	                  isReadOnly={isReadOnly}
 78	                  spans={fieldSpans}
 79	                  complexFields={complexFields}
 80	                  rowRenderer={rowRenderer}
 81	                  disableDeleteRow={disableDeleteRow}
 82	                  tooltipDeleteRow={tooltipDeleteRow}
 83	                  onDelete={() => remove(index)}
 84	                >
 85	                  {children}
 86	                </MultiColumnFieldRow>
 87	              ))}
 88	            {!isReadOnly && (
 89	              <MultiColumnFieldFooter
 90	                disableAddRow={disableAddRow}
 91	                tooltipAddRow={tooltipAddRow}
 92	                addLabel={addLabel}
 93	                onAdd={() => push(emptyValues)}
 94	              />
 95	            )}
 96	
 97	            <FormHelperText>
 98	              <HelperText>
 99	                <HelperTextItem>{helpText}</HelperTextItem>
100	              </HelperText>
101	            </FormHelperText>
102	          </FormGroup>
103	        );
104	      }}
105	    />
106	  );
107	};
108	
109	export default MultiColumnField;

